const source = (items[0] && items[0].json) ? items[0].json : {};
const docs = Array.isArray(source.result) ? source.result : [];

return docs
  .filter((doc) => doc && typeof doc === 'object')
  .map((doc) => ({ json: doc }));

const title = String($json.title || '').replace(/\s+/g, ' ').trim().slice(0, 180);
const excerpt = String($json.excerpt || '').replace(/\s+/g, ' ').trim().slice(0, 260);
const keyword = String($json.aiMeta?.targetKeyword || $json.aiMeta?.sourceTopicQuery || '').replace(/\s+/g, ' ').trim().slice(0, 140);
const subject = keyword || title || 'editorial feature';
const imageModel = String($env.IMAGE_MODEL || 'black-forest-labs/flux-schnell').trim();
const requestedAspectRatio = String($env.IMAGE_ASPECT_RATIO || '16:9').trim() || '16:9';
const supportedGptImageAspectRatios = new Set(['1:1', '3:2', '2:3']);
const isGptImage = imageModel.startsWith('openai/gpt-image-1.5');
const effectiveAspectRatio = isGptImage && !supportedGptImageAspectRatios.has(requestedAspectRatio)
  ? '3:2'
  : requestedAspectRatio;

const prompt = [
  'Photorealistic editorial hero image for a professional digital magazine article.',
  'Use a scene, subject, or setting that is specifically grounded in the article title and context.',
  'Primary subject: ' + subject + '.',
  title ? ('Article title: ' + title + '.') : '',
  excerpt ? ('Article context: ' + excerpt + '.') : '',
  'Choose a single coherent visual concept with realistic details, natural lighting, and strong magazine composition.',
  'Avoid generic office scenes unless the article itself clearly calls for them.',
  'No text overlay, no logos, no brand names, no watermark.',
  'Aspect ratio ' + effectiveAspectRatio + '.'
].filter(Boolean).join(' ');

return { json: { ...$json, imagePrompt: prompt, imageAspectRatio: effectiveAspectRatio } };

const nf = (typeof fetch === 'function') ? null : require('node-fetch');
const fetchFn = (typeof fetch === 'function') ? fetch : (nf.default || nf);
const { Buffer } = require('buffer');

function slugify(input) {
  return String(input || '')
    .toLowerCase()
    .trim()
    .replace(/["']/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 120);
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function predictionHasOutput(prediction) {
  return Array.isArray(prediction.output) ? prediction.output.length > 0 : Boolean(prediction.output);
}

async function fetchPrediction(url, replicateToken) {
  const response = await fetchFn(url, {
    headers: {
      Authorization: 'Token ' + replicateToken,
    },
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error('Failed to poll Replicate prediction (' + response.status + '): ' + text);
  }

  return response.json();
}

async function waitForPrediction(initialPrediction, replicateToken) {
  const maxPollAttempts = 12;
  const pollIntervalMs = 5000;
  let prediction = initialPrediction || {};

  for (let attempt = 0; attempt <= maxPollAttempts; attempt += 1) {
    if (predictionHasOutput(prediction)) return prediction;

    const status = String(prediction.status || 'unknown').toLowerCase();
    if (status === 'failed' || status === 'canceled') {
      throw new Error('Replicate prediction failed: ' + (prediction.error || prediction.status));
    }

    const pollUrl = String(prediction?.urls?.get || '').trim();
    if (!pollUrl) {
      break;
    }

    if (attempt === maxPollAttempts) {
      break;
    }

    await sleep(pollIntervalMs);
    prediction = await fetchPrediction(pollUrl, replicateToken);
  }

  throw new Error('Replicate prediction did not complete in time (status: ' + (prediction.status || 'unknown') + ').');
}

const article = $('Build Safe Image Prompt').item.json;
const replicateToken = String($env.REPLICATE_API_TOKEN || '').trim();
if (!replicateToken) {
  throw new Error('Missing REPLICATE_API_TOKEN env var');
}

const prediction = await waitForPrediction($json, replicateToken);
const outputUrl = Array.isArray(prediction.output) ? prediction.output[0] : prediction.output;
if (!outputUrl) {
  throw new Error('No image output URL from Replicate. Status: ' + prediction.status);
}

const imageRes = await fetchFn(outputUrl);
if (!imageRes.ok) {
  throw new Error('Failed to download generated image (' + imageRes.status + ')');
}
const imageBuffer = Buffer.from(await imageRes.arrayBuffer());
const contentType = imageRes.headers.get('content-type') || 'image/jpeg';

const apiVersion = $('Resolve Site Context').item.json.sanity.apiVersion || '2025-01-01';
const projectId = $('Resolve Site Context').item.json.sanity.projectId;
const dataset = $('Resolve Site Context').item.json.sanity.dataset || 'production';
const writeToken = $('Resolve Site Context').item.json.sanity.writeToken;
const imageModel = $env.IMAGE_MODEL || 'black-forest-labs/flux-schnell';

if (!projectId || !writeToken) {
  throw new Error('Missing Sanity env vars (SANITY_PROJECT_ID / SANITY_WRITE_TOKEN)');
}

const filename = slugify((article.slug && article.slug.current) || article.slug || article.title || 'article-hero') + '-hero.jpg';
const uploadUrl = 'https://' + projectId + '.api.sanity.io/v' + apiVersion + '/assets/images/' + dataset + '?filename=' + encodeURIComponent(filename);

const uploadRes = await fetchFn(uploadUrl, {
  method: 'POST',
  headers: {
    Authorization: 'Bearer ' + writeToken,
    'Content-Type': contentType,
  },
  body: imageBuffer,
});

if (!uploadRes.ok) {
  const text = await uploadRes.text();
  throw new Error('Sanity asset upload failed (' + uploadRes.status + '): ' + text);
}

const uploadJson = await uploadRes.json();
const assetId = uploadJson && uploadJson.document && uploadJson.document._id;
const assetUrl = uploadJson && uploadJson.document && uploadJson.document.url;

if (!assetId) {
  throw new Error('Sanity asset upload succeeded but asset id missing');
}

const altText = 'Editorial hero image for ' + article.title;
const mutateUrl = 'https://' + projectId + '.api.sanity.io/v' + apiVersion + '/data/mutate/' + dataset;

const patchBody = {
  mutations: [
    {
      patch: {
        id: article._id,
        set: {
          coverImage: {
            _type: 'image',
            asset: { _type: 'reference', _ref: assetId },
            aiPrompt: String(article.imagePrompt || '').slice(0, 400),
            modelVersion: imageModel,
          },
          coverImageAlt: altText,
        },
      },
    },
  ],
};

const patchRes = await fetchFn(mutateUrl, {
  method: 'POST',
  headers: {
    Authorization: 'Bearer ' + writeToken,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify(patchBody),
});

if (!patchRes.ok) {
  const text = await patchRes.text();
  throw new Error('Sanity article patch failed (' + patchRes.status + '): ' + text);
}

const patchJson = await patchRes.json();

return {
  json: {
    ...article,
    replicatePredictionId: prediction.id,
    imageOutputUrl: outputUrl,
    sanityAssetId: assetId,
    sanityAssetUrl: assetUrl,
    patchResult: patchJson,
    imageModel,
  }
};

const incoming = (typeof $json === 'object' && $json) ? $json : {};
const body = incoming.body && typeof incoming.body === 'object' ? incoming.body : {};
const payload = incoming.payload && typeof incoming.payload === 'object' ? incoming.payload : {};
const siteSlug = String(
  incoming.siteSlug ||
  incoming.site_slug ||
  body.siteSlug ||
  payload.siteSlug ||
  $env.SITE_SLUG ||
  ''
).trim().toLowerCase();
if (!siteSlug) {
  throw new Error('Missing siteSlug for Resolve Site Context');
}

const baseUrl = String($env.CONTENT_ENGINE_URL || '').replace(/\/$/, '');
if (!baseUrl) {
  throw new Error('Missing CONTENT_ENGINE_URL env var');
}

const internalToken = String($env.INTERNAL_API_TOKEN || '').trim();
if (!internalToken) {
  throw new Error('Missing INTERNAL_API_TOKEN env var');
}

const nf = (typeof fetch === 'function') ? null : require('node-fetch');
const fetchFn = (typeof fetch === 'function') ? fetch : (nf.default || nf);
const url = baseUrl + '/api/internal/sites/' + encodeURIComponent(siteSlug) + '/sanity-connection';

const response = await fetchFn(url, {
  method: 'GET',
  headers: {
    'x-internal-token': internalToken,
  },
});

const raw = await response.text();
let parsed = {};
try {
  parsed = raw ? JSON.parse(raw) : {};
} catch (error) {
  throw new Error('Invalid sanity-connection response for ' + siteSlug + ': ' + raw.slice(0, 220));
}

if (!response.ok || !parsed.ok || !parsed.sanity) {
  throw new Error('Cannot resolve site Sanity connection for ' + siteSlug + ': ' + (parsed.error || raw || response.status));
}

const sanity = parsed.sanity || {};
if (!sanity.projectId || !sanity.readToken || !sanity.writeToken) {
  throw new Error('Incomplete site Sanity connection for ' + siteSlug);
}

return {
  json: {
    ...incoming,
    siteSlug: parsed.siteSlug || siteSlug,
    sanity,
  }
};
